import{_ as a,o as p,c as n,a0 as e}from"./chunks/framework.jwovEGr5.js";const t="/assets/001_image_Ve9kbu40Eo.vWaCsND4.png",o="/assets/002_image_IaB9bqqj6o.DVjSqHT7.png",d="/assets/003_image_Idhdsahdl.jwCT8Fv3.png",m=JSON.parse('{"title":"第 1 章 初识 WorkBuddy ​","description":"","frontmatter":{},"headers":[],"relativePath":"p1/01.md","filePath":"p1/01.md"}'),r={name:"p1/01.md"};function i(l,s,c,_,u,k){return p(),n("div",null,[...s[0]||(s[0]=[e('<h1 id="第-1-章-初识-workbuddy-​" tabindex="-1">第 1 章 初识 WorkBuddy ​ <a class="header-anchor" href="#第-1-章-初识-workbuddy-​" aria-label="Permalink to &quot;第 1 章 初识 WorkBuddy ​&quot;">​</a></h1><p><strong>WorkBuddy</strong> 是腾讯最新推出的全场景职场 AI 智能体工作台，</p><p>面向 人力资源、行政、运营、销售、研发等不同职场角色，是一款能够像真正同事一样思考、执行任务并交付结果的 AI 办公应用。</p><p><img src="'+t+`" alt=""></p><h2 id="从-回答问题-到-交付结果-​" tabindex="-1">从“回答问题”到“交付结果” ​ <a class="header-anchor" href="#从-回答问题-到-交付结果-​" aria-label="Permalink to &quot;从“回答问题”到“交付结果” ​&quot;">​</a></h2><p>与传统 AI 助手不同，WorkBuddy 不只是陪用户聊天、回答问题或者给出建议。</p><p>用户只需要用一句自然语言描述需求，它就可以理解任务目标，在本地电脑中自主规划执行步骤，并完成复杂的多模态任务。</p><p>在获得用户授权后，WorkBuddy 可以读取和处理本地文件，自动完成批量文件处理、文档生成、表格分析、PPT 制作、多模态内容创作、行业调研、本地知识库构建等工作。</p><p>对于更加复杂的任务，它还可以自主拆解步骤，并通过多个智能体（Agents）并行，减少人工在不同工具、文件和任务之间反复切换的成本。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>flowchart LR</span></span>
<span class="line"><span>    A[说清目标] --&gt; B[读取授权资料]</span></span>
<span class="line"><span>    B --&gt; C[拆解任务与选择工具]</span></span>
<span class="line"><span>    C --&gt; D[执行并生成产物]</span></span>
<span class="line"><span>    D --&gt; E[人工验收]</span></span>
<span class="line"><span>    E --&gt;|不通过| F[指出问题并返工]</span></span>
<span class="line"><span>    F --&gt; D</span></span>
<span class="line"><span>    E --&gt;|通过| G[归档或发布]</span></span></code></pre></div><p>例如，用户可以直接告诉 WorkBuddy，分析这个文件夹中的销售数据，并生成一份汇报 PPT。</p><p><img src="`+o+'" alt=""></p><p>WorkBuddy 会自主读取相关文件，理解数据内容，完成分析和总结，并生成最终可以查看和修改的工作成果。</p><p>整个过程中，用户不需要手动上传每一个文件，也不需要一步一步告诉 AI 下一步应该做什么。</p><p>WorkBuddy 面向的是完整的工作任务。</p><p>它的核心能力可以概括为三点，<strong>听得懂人话，能够自主思考规划，也真的能够操作电脑交付成果。</strong></p><p>为了完成不同类型的任务，WorkBuddy 还提供了多模型切换（混元/DeepSeek/GLM/Kimi/MiniMax 等）、MCP Server、Skills 技能包等能力。</p><p>用户可以根据不同任务选择合适的模型，也可以通过 MCP 和 Skills 扩展 WorkBuddy 的工具和专业能力。</p><p>同时，针对本地文件操作、终端执行等场景，WorkBuddy 还提供高危指令拦截和权限控制机制，降低 AI 自主执行过程中的风险。</p><p>想对workbuddy打分，可以去观猹，写出你对workbuddy的真实评价～</p><p><img src="'+d+'" alt=""></p>',21)])])}const h=a(r,[["render",i]]);export{m as __pageData,h as default};
